    logger.info("=== Authentication API Server Starting ===")
    logger.warning(
        "SECURITY WARNING: This application logs sensitive authentication data "
        "including masked passwords. Ensure application.log is properly secured "
        "and this level of logging is disabled in production."
    )
    app.run(debug=True, host='0.0.0.0', port=5000)